mapper.update:
update purchase_supplier
supplier_name = #{supplierName}, supplier_code = #{supplierCode}, status = #{status}, sort_order = #{sortOrder}, remark = #{remark}, update_by = #{updateBy}, update_time = sysdate()
where supplier_id = #{supplierId}

update purchase_supplier_alias
supplier_id = #{supplierId}, alias_name = #{aliasName}, status = #{status}, remark = #{remark}, update_by = #{updateBy}, update_time = sysdate()
where alias_id = #{aliasId}

mapper.select:
select 
from purchase_manual_order
where del_flag='0'
and supplier_id = #{supplierId}
and order_no like concat('%', #{orderNo}, '%')
and product_model like concat('%', #{productModel}, '%')
and logistics_no like concat('%', #{logisticsNo}, '%')
and after_sale_flag = #{afterSaleFlag}
and invoice_status = #{invoiceStatus}
and reconciliation_status = #{reconciliationStatus}
and upload_user_name like concat('%', #{uploadUserName}, '%')
and data_status = #{dataStatus}
and order_date >= #{beginDate}
and order_date <= #{endDate}
order by manual_order_id desc

mapper.update:
update purchase_manual_order
supplier_id=#{supplierId}, supplier_name_snapshot=#{supplierNameSnapshot}, active_unique_key=#{activeUniqueKey}, order_date=#{orderDate}, order_no=#{orderNo}, product_model=#{productModel}, unit_price=#{unitPrice}, quantity=#{quantity}, total_amount=#{totalAmount}, customer_name=#{customerName}, customer_phone=#{customerPhone}, customer_address=#{customerAddress}, order_remark=#{orderRemark}, logistics_no=#{logisticsNo}, after_sale_flag=#{afterSaleFlag}, after_sale_request=#{afterSaleRequest}, balance_amount=#{balanceAmount}, receipt_status=#{receiptStatus}, payment_amount=#{paymentAmount}, invoice_status=#{invoiceStatus}, reconciliation_status=#{reconciliationStatus}, amount_check_status=#{amountCheckStatus}, data_status=#{dataStatus}, latest_upload_user_id=#{latestUploadUserId}, latest_upload_user_name=#{latestUploadUserName}, latest_upload_time=sysdate(), latest_source_file_name=#{latestSourceFileName}, latest_import_batch_id=#{latestImportBatchId}, latest_source_row_number=#{latestSourceRowNumber}, remark=#{remark}, update_by=#{updateBy}, update_time=sysdate()
where manual_order_id=#{manualOrderId}

mapper.select:
select 
from purchase_summary
where del_flag='0' and document_supplier_id=#{supplierId}
and purchase_order_remark=#{orderNo}

select 
from purchase_summary where del_flag='0' and match_status != 'SUCCESS'
and match_status=#{matchStatus}

mapper.update:
update purchase_summary
document_supplier_id=#{documentSupplierId}, document_supplier_name=#{documentSupplierName}, purchase_order_remark=#{purchaseOrderRemark}, contract_remark=#{contractRemark}, merchant_code=#{merchantCode}, purchase_quantity=#{purchaseQuantity}, original_logistics_no=#{originalLogisticsNo}, shipping_check_status=#{shippingCheckStatus}, exception_reason=#{exceptionReason}, purchaser_remark=#{purchaserRemark}, data_status=#{dataStatus}, latest_upload_user_id=#{latestUploadUserId}, latest_upload_user_name=#{latestUploadUserName}, latest_upload_time=sysdate(), latest_source_file_name=#{latestSourceFileName}, latest_import_batch_id=#{latestImportBatchId}, latest_source_row_number=#{latestSourceRowNumber}, remark=#{remark}, update_by=#{updateBy}, update_time=sysdate()
where summary_id=#{summaryId}

mapper.select:
select b.*, b.batch_id batchId, b.batch_no batchNo, b.import_type importType, b.supplier_id supplierId, b.original_file_name originalFileName, b.file_hash fileHash, b.sheet_name sheetName, b.total_rows totalRows, b.success_rows successRows, b.duplicate_rows duplicateRows, b.updated_rows updatedRows, b.conflict_rows conflictRows, b.failed_rows failedRows, b.match_success_rows matchSuccessRows, b.batch_status batchStatus, b.error_message errorMessage, b.upload_user_id uploadUserId, b.upload_user_name uploadUserName, b.upload_time uploadTime, b.finish_time finishTime, s.supplier_name supplierName from purchase_import_batch b left join purchase_supplier s on s.supplier_id=b.supplier_id
and b.import_type=#{importType} and b.batch_status=#{batchStatus}
order by b.batch_id desc

select * from purchase_match_log
where 1=1
and summary_id=#{summaryId}
and order_no like concat('%', #{orderNo}, '%')
and match_status=#{matchStatus}
order by log_id desc
